// Monta o corpo HTML do digest a partir das proposicoes retornadas pelo Postgres.
// Obs: o no Postgres tem 'Always Output Data' ligado - com 0 linhas ele emite
// um item vazio {}. Filtramos para nao virar linha fantasma no e-mail.
// HONESTIDADE NO PRODUTO: se a IA nao classificou/resumiu (tema ou resumo
// nulos no banco), o e-mail mostra isso explicitamente em vez de fingir.
const esc = s => String(s ?? '').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const itens = $input.all().map(i => i.json).filter(p => p && p.sigla_tipo);
const total = itens.length;
const totalDia = itens.length > 0 ? Number(itens[0].total_dia) : 0;
const hoje = new Date().toLocaleDateString('pt-BR');

let linhas = itens.map(p => {
  const titulo = `${p.sigla_tipo || ''} ${p.numero || ''}/${p.ano || ''}`.trim();
  const temaHtml = p.tema
    ? `<span style="background:#e8f0fe;color:#1a3e72;padding:2px 8px;border-radius:10px;font-size:12px;">${esc(p.tema)}</span>`
    : `<span style="background:#f1f1f1;color:#888;padding:2px 8px;border-radius:10px;font-size:12px;">Nao classificada</span>`;
  const resumoHtml = p.resumo_executivo
    ? esc(p.resumo_executivo)
    : `${esc(p.ementa_curta)} <small style="color:#b00020;">(ementa original — resumo IA pendente)</small>`;
  return `
    <tr>
      <td style="padding:8px;border-bottom:1px solid #eee;font-weight:600;">${esc(titulo)}</td>
      <td style="padding:8px;border-bottom:1px solid #eee;">${temaHtml}</td>
      <td style="padding:8px;border-bottom:1px solid #eee;color:#333;">${resumoHtml}</td>
    </tr>`;
}).join('');

if (total === 0) {
  linhas = `<tr><td colspan="3" style="padding:12px;color:#888;">Nenhuma proposicao nova nas ultimas 24h.</td></tr>`;
}

const html = `
  <div style="font-family:Arial,Helvetica,sans-serif;max-width:680px;margin:auto;">
    <h2 style="color:#1a3e72;">Bussola Publica — Radar Legislativo (${hoje})</h2>
    <p style="color:#444;">Pipeline executado com sucesso as 06h. <b>${totalDia}</b> proposicao(oes) nova(s) nas ultimas 24h — top <b>${total}</b> priorizadas abaixo, com tema e resumo executivo gerados por IA (GPT, uma chamada por proposicao).</p>
    <table style="border-collapse:collapse;width:100%;font-size:14px;">
      <thead>
        <tr style="background:#1a3e72;color:#fff;text-align:left;">
          <th style="padding:8px;">Proposicao</th>
          <th style="padding:8px;">Tema (IA)</th>
          <th style="padding:8px;">Resumo executivo (IA)</th>
        </tr>
      </thead>
      <tbody>${linhas}</tbody>
    </table>
    <p style="color:#999;font-size:12px;margin-top:16px;">Gerado automaticamente pelo pipeline Bussola Publica (n8n + Supabase + OpenAI).</p>
  </div>`;

return [{ json: { total, totalDia, hoje, html, assunto: `Bussola Publica — ${totalDia} proposicoes novas (${hoje})` } }];
